import pika
import json
import time
from threading import Thread

# Publisher class
class TaskPublisher:
    def __init__(self):
        self.connection = None
        self.channel = None
        self.setup_connection()
    
    def setup_connection(self):
        try:
            credentials = pika.PlainCredentials('guest', 'guest')
            parameters = pika.ConnectionParameters('localhost', 5672, '/', credentials)
            self.connection = pika.BlockingConnection(parameters)
            self.channel = self.connection.channel()
            self.channel.queue_declare(queue='task_queue', durable=True)
        except Exception as e:
            print(f"Error connecting to RabbitMQ: {e}")
    
    def publish_task(self, task_data):
        try:
            message = json.dumps(task_data)
            self.channel.basic_publish(
                exchange='',
                routing_key='task_queue',
                body=message,
                properties=pika.BasicProperties(
                    delivery_mode=2,  # make message persistent
                )
            )
            print(f"Published task: {task_data}")
        except Exception as e:
            print(f"Error publishing task: {e}")

# Consumer class
class TaskConsumer:
    def __init__(self, consumer_name):
        self.consumer_name = consumer_name
        self.connection = None
        self.channel = None
        self.setup_connection()
    
    def setup_connection(self):
        try:
            credentials = pika.PlainCredentials('guest', 'guest')
            parameters = pika.ConnectionParameters('localhost', 5672, '/', credentials)
            self.connection = pika.BlockingConnection(parameters)
            self.channel = self.connection.channel()
            self.channel.queue_declare(queue='task_queue', durable=True)
            self.channel.basic_qos(prefetch_count=1)
        except Exception as e:
            print(f"Error connecting to RabbitMQ: {e}")
    
    def process_task(self, ch, method, properties, body):
        try:
            task_data = json.loads(body)
            print(f"{self.consumer_name} processing task: {task_data}")
            
            # Simulate task processing
            time.sleep(2)
            
            print(f"{self.consumer_name} completed task: {task_data}")
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            print(f"Error processing task: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
    
    def start_consuming(self):
        try:
            self.channel.basic_consume(
                queue='task_queue',
                on_message_callback=self.process_task
            )
            print(f"{self.consumer_name} started consuming tasks...")
            self.channel.start_consuming()
        except Exception as e:
            print(f"Error starting consumer: {e}")

# Main application
def main():
    # Create publisher
    publisher = TaskPublisher()
    
    # Create consumers
    consumer1 = TaskConsumer("Consumer-1")
    consumer2 = TaskConsumer("Consumer-2")
    
    # Start consumers in separate threads
    consumer_thread1 = Thread(target=consumer1.start_consuming)
    consumer_thread2 = Thread(target=consumer2.start_consuming)
    
    consumer_thread1.daemon = True
    consumer_thread2.daemon = True
    
    consumer_thread1.start()
    consumer_thread2.start()
    
    # Publish some tasks
    tasks = [
        {"id": 1, "type": "email", "content": "Welcome email"},
        {"id": 2, "type": "notification", "content": "System update"},
        {"id": 3, "type": "report", "content": "Monthly summary"},
        {"id": 4, "type": "backup", "content": "Database backup"},
        {"id": 5, "type": "cleanup", "content": "Temporary files"}
    ]
    
    for task in tasks:
        publisher.publish_task(task)
        time.sleep(1)
    
    # Keep main thread alive
    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        print("Shutting down...")
        publisher.connection.close()

if __name__ == "__main__":
    main()